    const scrollY = window.scrollY;
    document.body.style.position = "fixed";
    document.body.style.width = "100%";
    document.body.style.top = `-${scrollY}px`;
  } else {
    // Restore the scroll position
    const scrollY = document.body.style.top;
    document.body.style.position = "";
    document.body.style.width = "";
    document.body.style.top = "";
    // window.scrollTo(0, Number.parseInt(scrollY || '0', 10) * -1); // THIS CAUSES A SCROLL BUG
  }
};

interface BuyButtonProps {
  className?: string;
  checkoutId?: string;
  storeId?: string;
}

export const BuyButton = ({ className, ...props }: BuyButtonProps) => {
  const checkoutId = props.checkoutId ?? "20b5b59e-b4c4-43b0-9979-545f90c76f28";
  const storeId = props.storeId ?? siteConfig.store.id;

  const { data: session } = useSession();
  const router = useRouter();
  const isScriptLoadedRef = useRef(false);

  // Stabilize session-dependent values
  const userId = session?.user?.id;
  const userEmail = session?.user?.email;

  // Memoize the event handler to prevent it from changing on every render
  const eventHandler = useCallback(
    async (event: LemonSqueezyEvent) => {
      if (!event?.event?.startsWith("Checkout")) {
        return;
      }

      logger.info("Lemon Squeezy event received", {
        checkoutId,
        event: event.event,
        orderId: event.data?.order?.data?.id,
        userId,
      });

      switch (event.event) {
        case "Checkout.Success": {
          const orderData = event.data.order.data;

          logger.info("Purchase successful", {
            checkoutId,
            orderId: orderData.id,
            userId,
            orderData: {
              identifier: orderData.attributes.identifier,
              status: orderData.attributes.status,
              total: orderData.attributes.total,
              productName: orderData.attributes.first_order_item.product_name,
            },
          });

          // Close the overlay
          window.LemonSqueezy?.Url.Close();
          // Re-enable scrolling
          toggleBodyScroll(false);

          try {
            logger.info("Creating payment record", {
              checkoutId,
              orderId: orderData.id,
              userId,
            });

            // Call server action to create payment record
            const result = await createLemonSqueezyPayment({
              orderId: orderData.attributes.identifier, // Use identifier as primary orderId
              orderIdentifier: orderData.attributes.identifier, // Keep for backward compatibility
              userId,
              userEmail: orderData.attributes.user_email || undefined,
              customData: event.data.custom_data,
              status: orderData.attributes.status,
              total: orderData.attributes.total,
              productName: orderData.attributes.first_order_item?.product_name || "Unknown Product",
            });

            logger.info("Payment record created successfully", {
              checkoutId,
              orderId: orderData.id,
              userId,
              result,
            });

            toast.success("Payment processed! Redirecting to dashboard...");
            router.push(routes.app.dashboard);
          } catch (error) {
            logger.error("Error creating payment record", {
              checkoutId,
              orderId: orderData.id,
              userId,
              error: error instanceof Error ? error.message : String(error),
              stack: error instanceof Error ? error.stack : undefined,
            });

            // Fallback to success page redirect if API fails
            const successUrl = new URL(routes.checkoutSuccess, window.location.origin);

            // Add order data to URL
            successUrl.searchParams.set("order_id", orderData.attributes.identifier);
            successUrl.searchParams.set("email", orderData.attributes.user_email || "");
            successUrl.searchParams.set("status", orderData.attributes.status);

            // Add custom data that was passed during checkout
            if (userId) {
              const customData = {
                user_id: userId,
                user_email: userEmail,
              };
              successUrl.searchParams.set("custom_data", JSON.stringify(customData));
            }

            toast.error(
              "There was an issue processing your payment. Redirecting to order confirmation..."
            );
            router.push(successUrl.toString());
          }
          break;
        }
        case "Checkout.Closed": {
          logger.info("Checkout closed", {
            checkoutId,
            userId,
          });
          break;
        }
        default: {
          logger.info("Unknown event", {
            checkoutId,
            event: event.event,
          });
        }
      }

      toggleBodyScroll(false); // Re-enable scrolling
    },
    [checkoutId, userId, userEmail, router]
  );

  useEffect(() => {
    // Prevent duplicate script loading
    if (isScriptLoadedRef.current) {
      return;
    }

    // Load Lemon.js script
    const script = document.createElement("script");
    script.src = "https://app.lemonsqueezy.com/js/lemon.js";
    script.defer = true;
    document.body.appendChild(script);

    script.onload = () => {
      // Initialize Lemon.js
      window.createLemonSqueezy?.();

      // Setup event handlers
      window?.LemonSqueezy?.Setup({
        eventHandler,
      });

      isScriptLoadedRef.current = true;
    };

    script.onerror = (error) => {
      logger.error("Error loading Lemon.js script", {
        checkoutId,
        error: String(error),
      });
    };

    return () => {
      logger.info("Cleaning up BuyButton", { checkoutId });
      // Only remove script if it was added by this component
      if (script.parentNode) {
        document.body.removeChild(script);
      }
      toggleBodyScroll(false); // Ensure scrolling is re-enabled on unmount
      isScriptLoadedRef.current = false;
    };
  }, [checkoutId, eventHandler]);

  const handleClick = () => {
    logger.info("Buy button clicked", {
      checkoutId,
      userId,
      userEmail,
    });

    // Use the configured checkout URL from site config
    // This ensures we're using the correct variant ID for checkout
    const checkoutUrl = new URL(`https://${storeId}.lemonsqueezy.com/checkout/buy/${checkoutId}`);

    // Add success page URL
    const successUrl = new URL(routes.checkoutSuccess, window.location.origin);
    checkoutUrl.searchParams.set("checkout[success_url]", successUrl.toString());

    if (userEmail) {
      // Add user data
      checkoutUrl.searchParams.set("checkout[custom][user_email]", userEmail);
      if (userId) {
        checkoutUrl.searchParams.set("checkout[custom][user_id]", userId);
      }
      // Pre-fill the email field
      checkoutUrl.searchParams.set("checkout[email]", userEmail);
    }

    logger.info("Opening checkout", {
      checkoutId,
      userId,
      checkoutUrl: checkoutUrl.toString(),
    });

    // Disable scrolling before opening the overlay
    toggleBodyScroll(true);
    // Open the checkout overlay with dark theme
    checkoutUrl.searchParams.set("dark", "1");
    window.LemonSqueezy?.Url.Open(checkoutUrl.toString());
  };

  return (
    <>
      <Button onClick={handleClick} variant="default" className={cn(className)}>
        Get {siteConfig.title}
      </Button>
    </>
  );
};

"use client";

import { AlertCircle, CheckCircle, ExternalLink } from "lucide-react";
import { useSession } from "next-auth/react";
import { useCallback, useEffect, useState } from "react";
import { toast } from "sonner";
import { Icons } from "@/components/assets/icons";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Button } from "@/components/ui/button";
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from "@/components/ui/card";
import { createPolarCheckoutUrl } from "@/server/actions/payments";

// Helper to check purchase status via API
async function checkUserPurchasedProduct(
  productId: string,
  provider?: "lemonsqueezy" | "polar"
): Promise<{ success: boolean; purchased: boolean; message?: string }> {
  const params = new URLSearchParams({ productId });
  if (provider) params.set("provider", provider);

  const response = await fetch(`/api/payments/check-purchase?${params}`);
  if (!response.ok) {
    return { success: false, purchased: false, message: "Failed to check purchase status" };
  }
  return response.json();
}

// Simple cache to prevent repeated API calls
const productStatusCache = new Map<string, { data: boolean; timestamp: number }>();
const CACHE_DURATION = 5 * 60 * 1000; // 5 minutes

interface PolarProductStatusProps {
  productId: string;
  productName: string;
  productDescription?: string;
  productPrice?: string;
  redirectUrl?: string;
  checkoutUrl?: string;
  className?: string;
  buttonText?: string;
  buttonUrl?: string;
  loadingText?: string;
  successText?: string;
}

export function PolarProductStatus({
  productId,
  productName,
  productDescription,
  productPrice,
  redirectUrl,
  checkoutUrl,
  className,
  buttonText = "Purchase Now",
  buttonUrl = "",
  loadingText = "Checking purchase status...",
  successText = "Purchased",
}: PolarProductStatusProps) {
  const { data: session } = useSession();
  const [isPurchased, setIsPurchased] = useState<boolean | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Memoize the check function to prevent unnecessary re-renders
  const checkPurchaseStatus = useCallback(async () => {
    if (!session?.user?.id) {
      setIsLoading(false);
      return;
    }

    // Check cache first
    const cacheKey = `${session.user.id}-${productId}`;
    const cached = productStatusCache.get(cacheKey);
    const now = Date.now();

    if (cached && now - cached.timestamp < CACHE_DURATION) {
      setIsPurchased(cached.data);
      setIsLoading(false);
      return;
    }

    try {
      setIsLoading(true);
      const result = await checkUserPurchasedProduct(productId, "polar");

      if (result.success) {
        // Cache the result
        productStatusCache.set(cacheKey, {
          data: result.purchased,
          timestamp: now,
        });

        setIsPurchased(result.purchased);
      } else {
        setError(result.message || "Failed to check purchase status");
      }
    } catch (err) {
      setError("An error occurred while checking purchase status");
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  }, [session?.user?.id, productId]);

  // Check if user has purchased this product
  useEffect(() => {
    if (session?.user?.id) {
      checkPurchaseStatus();
    }
  }, [session?.user?.id, productId, checkPurchaseStatus]);

  const handlePurchase = async () => {
    if (!session?.user?.id) {
      toast.error("Please sign in to purchase this product");
      return;
    }

    setIsLoading(true);
    try {
      // If checkoutUrl is provided, redirect to it
      if (checkoutUrl) {
        window.location.href = checkoutUrl;
        return;
      }

      // Use the server action to generate a checkout URL
      const result = await createPolarCheckoutUrl(productId);

      if (result.success && result.url) {
        window.location.href = result.url;
      } else {
        toast.error(result.message || "Failed to create checkout URL");
      }
    } catch (error) {
      console.error("Error creating checkout:", error);
      toast.error("Failed to initiate checkout");
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <div className="flex items-center space-x-2">
        <Icons.spinner className="h-4 w-4 animate-spin" />
        <span className="text-sm text-muted-foreground">{loadingText}</span>
      </div>
    );
  }

  if (error) {
    return (
      <Alert variant="destructive" className="mt-2">
        <AlertCircle className="h-4 w-4" />
        <AlertDescription>{error}</AlertDescription>
      </Alert>
    );
  }

  if (isPurchased) {
    return (
      <div className="flex items-center space-x-2">
        <CheckCircle className="h-4 w-4 text-green-500" />
        <span className="text-sm font-medium">{successText}</span>
      </div>
    );
  }

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle>{productName}</CardTitle>
        {productDescription && <CardDescription>{productDescription}</CardDescription>}
      </CardHeader>
      <CardContent>
        <div className="space-y-2">
          {productPrice && <p className="font-semibold">{productPrice}</p>}
          <p className="text-sm text-muted-foreground">You haven't purchased this product yet.</p>
        </div>
      </CardContent>
      <CardFooter>
        <Button
          size="sm"
          variant="outline"
          onClick={handlePurchase}
          disabled={isLoading || !session?.user}
        >
          {isLoading ? (
            <>
              <Icons.spinner className="mr-2 h-4 w-4 animate-spin" />
              Processing...
            </>
          ) : (
            <>
              {buttonText}
              {buttonUrl && <ExternalLink className="ml-2 h-4 w-4" />}
            </>
          )}
        </Button>
      </CardFooter>
    </Card>
  );
}
